import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { handleError, handleSuccess } from '../utils';
import { ToastContainer } from 'react-toastify';
import './home.css';  // Assurez-vous de lier le fichier CSS

function Home() {
  const [loggedInUser, setLoggedInUser] = useState('');
  const [userProfile, setUserProfile] = useState(null);
  const [isLoading, setIsLoading] = useState(true);  // Ajout de l'état de chargement
  const navigate = useNavigate();

  useEffect(() => {
    const userId = localStorage.getItem('loggedInUserId');
    console.log("Logged in user ID:", userId);  // Log pour vérifier userId
    setLoggedInUser(localStorage.getItem('loggedInUser'));

    if (userId) {
      fetchUserProfile(userId);
    } else {
      handleError("User ID not found in localStorage");
      navigate('/login');  // Optionnel: redirige vers la page de login si l'ID utilisateur est introuvable
    }
  }, []);

  const fetchUserProfile = async (userId) => {
    try {
      const response = await axios.get(`http://localhost:5001/users/${userId}`);
      console.log('API Response:', response.data);  // Afficher la réponse de l'API

      if (response.data.success) {
        setUserProfile(response.data.user);
      } else {
        handleError('User not found');
      }
    } catch (error) {
      handleError('Failed to fetch user profile');
      console.error('Error fetching user profile:', error);  // Afficher l'erreur
    } finally {
      setIsLoading(false);  // Fin du chargement
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('loggedInUser');
    localStorage.removeItem('loggedInUserId');  // Remove user ID
    handleSuccess('User Logged out');
    setTimeout(() => {
      navigate('/login');
    }, 1000);
  };

  console.log('isLoading:', isLoading);  // Vérification de l'état de chargement

  return (
    <div className="home-container">
      {/* Sidebar */}
      <div className="sidebar">
        <div className="logo">MyApp</div>
        <ul>
          <li><a href="/home">Home</a></li>
          <li><a href="/profile">Profile</a></li>
          <li><a href="/products">Products</a></li>
        </ul>
      </div>

      {/* Main Content */}
      <div className="main-content">
        {/* Header */}
        <div className="header">
          <h1>Welcome, {loggedInUser}</h1>
          <button onClick={handleLogout} className="logout-btn">Logout</button>
        </div>

        {/* User Profile */}
        {isLoading ? (
          <div className="loading">Loading...</div>  // Afficher un message de chargement
        ) : userProfile ? (
          <div className="profile-section">
            <div className="profile-header">
              <img src="https://via.placeholder.com/150" alt="User" className="profile-img" />
              <div className="profile-info">
                <h3>{userProfile.name}</h3>
                <p><strong>Email:</strong> {userProfile.email}</p>
                <p><strong>Role:</strong> {userProfile.role}</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="error-message">User profile could not be loaded</div>  // Message d'erreur si le profil n'est pas trouvé
        )}
      </div>

      <ToastContainer />
    </div>
  );
}

export default Home;
